// Worked focus: cmem-calloc-overflow-contract — Characterize whether the target calloc detects product overflow while retaining caller-side policy and tests.
/* Evidence: cmem-worked-cmem-allocation-size-overflow-4 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 5473; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_allocation_size_overflow_4(size_t header, size_t count, size_t width, size_t limit, size_t *total) {
  size_t payload;
  if (total == NULL || width == 0 || count > limit / width) return 0;
  payload = count * width;
  if (header > limit - payload) return 0;
  *total = header + payload;
  return 1;
}

int main(void) {
  size_t total = 0;
  int rejected = worked_cmem_allocation_size_overflow_4(16, 20, 8, 100, &total);
  int accepted = worked_cmem_allocation_size_overflow_4(8, 6, 4, 100, &total);
  int invariant = !rejected && accepted && total == (size_t)32;
  printf("allocation total=%lu invariant=%d\n", (unsigned long)total, invariant);
  return invariant ? 0 : 1;
}

